    slug:         "thomas-v-henry-county-water-auth-a23a0362",
    title:        "Thomas v. Henry County Water Auth.",
    shortTitle:   "Thomas v. Henry County Water Auth.",
    court:        "Court of Appeals of Georgia",
    docketNumber: "A23A0362",
    dateDecided:  "April 18, 2023",
    citations:    "367 Ga. App. 469 *; 886 S.E.2d 857 **; 2023 Ga. App. LEXIS 168 ***; 2023 WL 2983097",
    judges:       "MERCIER, Judge. Miller, P. J., and Hodges, J., concur.",
    disposition:  "Judgment reversed.",
