    id:           "wright-v-state-s22a1117",
    slug:         "wright-v-state-s22a1117",
    title:        "Wright v. State",
    shortTitle:   "Wright v. State",
    court:        "Supreme Court of Georgia",
    docketNumber: "S22A1117",
    dateDecided:  "January 18, 2023",
    citations:    "315 Ga. 459 *; 883 S.E.2d 294 **; 2023 Ga. LEXIS 12 ***",
    judges:       "BOGGS, Chief Justice. All the Justices concur.",
    disposition:  "Judgment affirmed.",
