    id:           "state-v-harris-s23a0090s23a0091",
    slug:         "state-v-harris-s23a0090-s23a0091",
    title:        "State v. Harris",
    shortTitle:   "State v. Harris",
    court:        "Supreme Court of Georgia",
    docketNumber: "S23A0090, S23A0091",
    dateDecided:  "May 16, 2023",
    citations:    "316 Ga. 272 *; 888 S.E.2d 50 **; 2023 Ga. LEXIS 103 ***",
    judges:       "BETHEL, Justice. All the Justices concur.",
    disposition:  "Judgments vacated and cases remanded with direction in Case Nos. S23A0090 and S23A0091.",
